const body = $input.first().json;
let extracted = body.extracted;
if (typeof extracted === 'string') {
  try { extracted = JSON.parse(extracted); } catch(e) { extracted = {}; }
}

const typeMap = {
  'rumah': { type: 'Rumah Tinggal', defaultTier: 'Standar' },
  'cafe': { type: 'Cafe / Restoran', defaultTier: 'Standar' },
  'restoran': { type: 'Cafe / Restoran', defaultTier: 'Standar' },
  'kantor': { type: 'Kantor', defaultTier: 'Standar' },
  'villa': { type: 'Villa / Guest House', defaultTier: 'Standar' },
  'ruko': { type: 'Ruko / Kios', defaultTier: 'Standar' },
  'renovasi': { type: 'Renovasi (Parsial)', defaultTier: 'Sedang' }
};

const tierMap = {
  'ekonomi': 'Ekonomi', 'standar': 'Standar', 'menengah': 'Menengah Atas',
  'premium': 'Premium', 'mewah': 'Mewah/Premium', 'ringan': 'Ringan', 'sedang': 'Sedang'
};

const serviceMap = {
  'arsitektur': 'Arsitektur', 'interior': 'Interior', 'komersial': 'Komersial',
  'lansekap': 'Lansekap', 'pengawasan': 'Pengawasan'
};

const autoServiceMap = {
  'cafe': 'Komersial', 'restoran': 'Komersial', 'renovasi': 'Interior',
  'villa': 'Arsitektur', 'rumah': 'Arsitektur', 'kantor': 'Arsitektur', 'ruko': 'Arsitektur'
};

const rawType = (extracted.building_type || '').toLowerCase();
const rawTier = (extracted.tier || '').toLowerCase();
const rawService = (extracted.service_type || '').toLowerCase();

const typeInfo = typeMap[rawType] || { type: 'Rumah Tinggal', defaultTier: 'Standar' };
const normalizedTier = tierMap[rawTier] || typeInfo.defaultTier;
const normalizedService = serviceMap[rawService] || autoServiceMap[rawType] || 'Arsitektur';

return [{
  json: {
    from: body.from,
    clientName: body.clientName || 'kak',
    phoneNumberId: body.phoneNumberId || '1052743247932102',
    buildingType: typeInfo.type,
    tier: normalizedTier,
    areaSqm: extracted.area_sqm || null,
    serviceCategory: normalizedService
  }
}];

const inputData = $('Normalize Extracted Data').first().json;
const rabRows = $('Sheets — Read RAB').all().map(function(i) { return i.json; });
const feeRows = $('Sheets — Read Fee').all().map(function(i) { return i.json; });

const buildingType = inputData.buildingType;
const tier = inputData.tier;
const areaSqm = inputData.areaSqm;
const serviceCategory = inputData.serviceCategory;

console.log('RAB columns:', Object.keys(rabRows[0] || {}));
console.log('Looking for:', buildingType, tier);

// Cari baris RAB
var rabRow = null;
for (var i = 0; i < rabRows.length; i++) {
  var r = rabRows[i];
  var vals = Object.values(r);
  var rowType = String(vals[0] || '').toLowerCase().trim();
  var rowTier = String(vals[1] || '').toLowerCase().trim();
  var btLower = buildingType.toLowerCase().split('/')[0].trim();
  var tierLower = tier.toLowerCase().split('/')[0].trim();
  if (rowType.indexOf(btLower) !== -1 && rowTier.indexOf(tierLower) !== -1) {
    rabRow = r; break;
  }
}
if (!rabRow) {
  for (var j = 0; j < rabRows.length; j++) {
    var r2 = rabRows[j];
    var rowType2 = String(Object.values(r2)[0] || '').toLowerCase();
    if (rowType2.indexOf(buildingType.toLowerCase().split('/')[0].trim()) !== -1) {
      rabRow = r2; break;
    }
  }
}
if (!rabRow) rabRow = rabRows[1] || rabRows[0] || {};

var cleanNum = function(val) {
  if (typeof val === 'number') return val;
  return parseFloat(String(val).replace(/[^0-9.]/g, '')) || 0;
};

var rabVals = Object.values(rabRow);
var rabPriceMin = cleanNum(rabVals[2] || 0);
var rabPriceMax = cleanNum(rabVals[3] || 0);
var area = areaSqm || 100;
var rabMin = rabPriceMin * area;
var rabMax = rabPriceMax * area;
var rabAvg = (rabMin + rabMax) / 2;
var spec = String(rabVals[4] || '');

// Cari baris Fee
var feeRow = null;
for (var k = 0; k < feeRows.length; k++) {
  var f = feeRows[k];
  var rowCat = String(Object.values(f)[0] || '').toLowerCase();
  var catLower = serviceCategory.toLowerCase();
  if (rowCat.indexOf(catLower) !== -1 || rowCat.indexOf(catLower.split('/')[0].trim()) !== -1) {
    feeRow = f; break;
  }
}
if (!feeRow) feeRow = feeRows[0] || {};

var feePctRaw = Object.values(feeRow)[2] || 7;
var feePctStr = String(feePctRaw).replace('%', '').trim();
var feePctMin, feePctMax;
if (feePctStr.indexOf('-') !== -1) {
  var parts = feePctStr.split('-');
  feePctMin = parseFloat(parts[0]) || 7;
  feePctMax = parseFloat(parts[1]) || 10;
} else {
  feePctMin = feePctMax = parseFloat(feePctStr) || 7;
}

var feeMin = rabAvg * feePctMin / 100;
var feeMax = rabAvg * feePctMax / 100;
var feeAvg = (feeMin + feeMax) / 2;
var ppn = feeAvg * 0.11;
var totalFee = feeAvg + ppn;

var fmt = function(n) {
  if (n >= 1000000000) return 'Rp ' + (n/1000000000).toFixed(1) + ' M';
  if (n >= 1000000) return 'Rp ' + Math.round(n/1000000) + ' jt';
  return 'Rp ' + n.toLocaleString('id-ID');
};

return [{
  json: {
    from: inputData.from,
    clientName: inputData.clientName,
    phoneNumberId: inputData.phoneNumberId,
    area: area,
    result: {
      buildingType: buildingType, tier: tier, areaSqm: area, spec: spec,
      rabMin: rabMin, rabMax: rabMax, rabAvg: rabAvg,
      rabMinFmt: fmt(rabMin), rabMaxFmt: fmt(rabMax), rabAvgFmt: fmt(rabAvg),
      serviceCategory: serviceCategory,
      feePctMin: feePctMin, feePctMax: feePctMax,
      feeMin: feeMin, feeMax: feeMax, feeAvg: feeAvg,
      feeMinFmt: fmt(feeMin), feeMaxFmt: fmt(feeMax), feeAvgFmt: fmt(feeAvg),
      ppn: ppn, ppnFmt: fmt(ppn),
      totalFee: totalFee, totalFeeFmt: fmt(totalFee),
      areaAssumed: !areaSqm
    }
  }
}];

var r = $json.result;
var name = ($json.clientName || 'kak').split(' ')[0];
var areaNote = r.areaAssumed ? '\n(estimasi berdasarkan luas 100m2, sesuaikan kalau beda ya)' : '';
var feeRange = r.feePctMin !== r.feePctMax ? r.feePctMin + '-' + r.feePctMax + '%' : r.feePctMin + '%';
var feeDisplay = r.feePctMin !== r.feePctMax ? r.feeMinFmt + ' - ' + r.feeMaxFmt : r.feeAvgFmt;

var replyText = 'Halo ' + name + ', ini estimasi kasarnya ya.' +
  '\n\nProyek: ' + r.buildingType + ' ' + r.tier +
  '\nLuas: ' + r.areaSqm + 'm2' + areaNote +
  (r.spec ? '\nSpesifikasi: ' + r.spec : '') +
  '\n\nEstimasi RAB Konstruksi:' +
  '\n' + r.rabMinFmt + ' - ' + r.rabMaxFmt +
  '\n(rata-rata ' + r.rabAvgFmt + ')' +
  '\n\nFee Jasa Desain Sudut Ruang (' + feeRange + ' dari RAB):' +
  '\n' + feeDisplay +
  '\n\nPPN 11%: ' + r.ppnFmt +
  '\nTotal Fee Jasa: ' + r.totalFeeFmt +
  '\n\nIni masih estimasi awal ya, bisa berubah setelah survey dan diskusi detail.' +
  '\n\nMau kita buatkan proposal lengkap?';

return [{ json: { ...$json, replyText: replyText } }];
